def test_uuid_field_invalid_format(client) -> None:
    """Tests UUID field with invalid UUID format."""
    response = client.post(
        "/items/",
        json={"item_id": "not-a-valid-uuid", "name": "Item"},
        headers={
            "Content-Type": "application/json",
        },
    )
    assert response.status_code == 422  # noqa: S101
    data = response.json()
    assert data == {"detail": "1 validation error in request", "errors": [{"input": "not-a-valid-uuid", "loc": ["body", "item_id"], "msg": "Input should be a valid UUID", "type": "uuid_parsing"}], "status": 422, "title": "Request Validation Failed", "type": "https://spikard.dev/errors/validation-error"}  # noqa: S101

def test_uuid_field_success(client) -> None:
    """Tests UUID field with valid UUID format."""
    response = client.post(
        "/items/",
        json={"item_id": "c892496f-b1fd-4b91-bdb8-b46f92df1716", "name": "Item"},
        headers={
            "Content-Type": "application/json",
        },
    )
    assert response.status_code == 200  # noqa: S101
    data = response.json()
    assert data == {"item_id": "c892496f-b1fd-4b91-bdb8-b46f92df1716", "name": "Item"}  # noqa: S101

